query:
-- Apollo credits used today
SELECT COUNT(*) as apolloRevealsToday, SUM(creditsUsed) as totalCreditsUsed
FROM apolloCreditLog
WHERE DATE(createdAt) = '2026-06-02';

-- New projects created today
SELECT COUNT(*) as newProjectsToday FROM projects WHERE DATE(createdAt) = '2026-06-02';

-- New contacts created today  
SELECT COUNT(*) as newContactsToday FROM contacts WHERE DATE(createdAt) = '2026-06-02';

-- Current send_ready total
SELECT COUNT(*) as totalSendReady FROM contacts WHERE trustTier = 'send_ready';

-- Hot projects with send_ready contacts
SELECT COUNT(DISTINCT p.id) as hotProjectsWithContacts
FROM projects p
JOIN contactProjects cp ON cp.projectId = p.id
JOIN contacts c ON c.id = cp.contactId
WHERE p.priority = 'hot' AND c.trustTier = 'send_ready';

-- Total hot projects
SELECT COUNT(*) as totalHotProjects FROM projects WHERE priority = 'hot' AND status = 'active';

